VALUES
  ('heelevel3-7be5e2bb-moex-00103', 'heelevel3-7be5e2bb', 'heelevel3-7be5e2bb-moex-112-3082b5f1', 'sub-heelevel3-7be5e2bb-02', NULL, 'single_choice', '關於受託行使公權力之私人或團體，下列敘述何者錯誤？', '["受委託者於受託範圍內得作出行政處分", "授權之法律有明定受託者得訂定法規命令者，受託之私人或團體不需委託機關特別授權，即得 發布法規命令", "受委託者即使無法律授權，亦得將其受託之權限再委託其他私人或團體", "受委託者於受託範圍內得立於機關之地位作出事實行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:48+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "316", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "體育行政"}'::jsonb, NULL),
  ('heelevel3-7be5e2bb-moex-00104', 'heelevel3-7be5e2bb', 'heelevel3-7be5e2bb-moex-112-3082b5f1', 'sub-heelevel3-7be5e2bb-02', NULL, 'single_choice', '財政部以營利事業欠稅為由，函請內政部移民署限制營利事業負責人出境，並通知營利事業負責 人。下列敘述何者錯誤？', '["限制出境之決定乃係行政處分", "限制出境之決定係內政部移民署所作成的行政處分", "內政部移民署所為限制出境之決定屬多階段行政處分", "營利事業負責人不得以不服財政部通知為由向行政院提起訴願"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:48+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "316", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "體育行政"}'::jsonb, NULL),
  ('heelevel3-7be5e2bb-moex-00105', 'heelevel3-7be5e2bb', 'heelevel3-7be5e2bb-moex-112-3082b5f1', 'sub-heelevel3-7be5e2bb-02', NULL, 'single_choice', '行政機關發現經其核准受領疫情紓困補助的受益人，有重複領取情形，於其撤銷原處分後，應採 取何種方式追回溢發之款項？', '["作成書面行政處分確認返還範圍，並限期命受益人返還", "向行政法院提起一般給付訴訟", "向民事法院提起請求返還不當得利訴訟", "直接移送法務部行政執行署所屬分署執行"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:48+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "316", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "體育行政"}'::jsonb, NULL),
  ('heelevel3-7be5e2bb-moex-00106', 'heelevel3-7be5e2bb', 'heelevel3-7be5e2bb-moex-112-3082b5f1', 'sub-heelevel3-7be5e2bb-02', NULL, 'single_choice', '行政處分於法定救濟期間經過後，當事人仍得於一定情形下申請撤銷、廢止或變更之。下列敘述 何者錯誤？', '["具有持續效力之行政處分，其依據之事實事後發生有利變更者，相對人或利害關係人得提出申請", "該項申請應自法定救濟期間經過後3個月內為之", "雖有重新開始程序之原因，行政機關如認為原處分為正當者，仍應駁回該申請", "相對人或利害關係人因過失未能在行政程序中主張其事由者，即不得提出該項申請"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:48+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "316", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "體育行政"}'::jsonb, NULL),
  ('heelevel3-7be5e2bb-moex-00107', 'heelevel3-7be5e2bb', 'heelevel3-7be5e2bb-moex-112-3082b5f1', 'sub-heelevel3-7be5e2bb-02', NULL, 'single_choice', '有關行政契約，下列敘述何者錯誤？', '["行政程序法所規定的行政契約類型，有和解契約與雙務契約", "行政機關與人民締結行政契約後，為確保人民信賴利益，不得調整契約內容與終止契約", "行政契約之締結，原則上須以書面為之", "行政契約中，如行政機關與人民互負給付義務，雙方之給付應相當，且具備合理關聯"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:48+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "316", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "體育行政"}'::jsonb, NULL),
  ('heelevel3-7be5e2bb-moex-00108', 'heelevel3-7be5e2bb', 'heelevel3-7be5e2bb-moex-112-3082b5f1', 'sub-heelevel3-7be5e2bb-02', NULL, 'single_choice', '下列何者屬於行政事實行為？', '["拆除違章建築", "行政院發布徵兵規則", "警察指揮交通", "行人穿越道之交通標線"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:48+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "316", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "體育行政"}'::jsonb, NULL),
  ('heelevel3-7be5e2bb-moex-00109', 'heelevel3-7be5e2bb', 'heelevel3-7be5e2bb-moex-112-3082b5f1', 'sub-heelevel3-7be5e2bb-02', NULL, 'single_choice', '藥事法規定不具藥商資格販賣藥品者，處新臺幣3萬元以上200萬元以下罰鍰。甲於網路上販售從 國外買回的藥品，被查獲違反前述藥事法規定，其請求依據行政罰法第19條規定免予處罰，承辦 此案之公務人員應如何處理？', '["若甲販賣藥品之獲利低於3萬元，得免予處罰", "若甲為初次違規，得免予處罰", "若藥品尚未售出，得免予處罰", "甲之情形無法適用行政罰法第19條免予處罰之規定 31550、31650 32250、32950 33050 33850"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:48+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "316", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "體育行政"}'::jsonb, NULL),
  ('heelevel3-7be5e2bb-moex-00110', 'heelevel3-7be5e2bb', 'heelevel3-7be5e2bb-moex-112-3082b5f1', 'sub-heelevel3-7be5e2bb-02', NULL, 'single_choice', '甲積欠交通違規罰單新臺幣18,000元，主管機關經催繳後仍未繳納，移送行政執行。依行政執行 法之規定，下列敘述何者正確？', '["如甲於執行程序終結前死亡，未留有遺產，執行機關應向甲之繼承人為執行", "如甲於執行程序終結前繳清罰鍰，其應以聲明異議之方式請求終止執行", "如執行機關發現甲顯有財產卻故意不繳納，且已出境1次，得限制甲之住居", "如甲對於執行機關限制住居之命令不服，經聲明異議遭駁回後，得直接提起撤銷訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:48+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "316", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "體育行政"}'::jsonb, NULL),
  ('heelevel3-7be5e2bb-moex-00111', 'heelevel3-7be5e2bb', 'heelevel3-7be5e2bb-moex-112-3082b5f1', 'sub-heelevel3-7be5e2bb-02', NULL, 'single_choice', '依據政府資訊公開法，關於政府資訊公開，下列敘述何者錯誤？', '["政府資訊可由政府機關主動公開，亦得應人民申請被動公開", "申請政府資訊之公開，不以主張或維護法律上利益有必要為前提", "對於政府資訊公開申請之決定不服者，得依法提起行政救濟", "經申請公開之政府資訊涉及第三人權益，經其明確表示不同意公開時，政府機關應即作成不予 公開之決定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:48+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "316", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "體育行政"}'::jsonb, NULL),
  ('heelevel3-7be5e2bb-moex-00112', 'heelevel3-7be5e2bb', 'heelevel3-7be5e2bb-moex-112-3082b5f1', 'sub-heelevel3-7be5e2bb-02', NULL, 'single_choice', '下列何者非訴願審理機關審理訴願案件應遵循之原則？', '["書面審查原則", "職權調查原則", "不利益變更禁止原則", "停止執行原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:48+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "316", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "體育行政"}'::jsonb, NULL)
